     1→"use client";
     2→
     3→import { Suspense } from "react";
     4→import { useCallback, useEffect, useRef, useState } from "react";
     5→import { QRCodeSVG } from "qrcode.react";
     6→import { useCamera } from "@/hooks/useCamera";
     7→import { useGestureRecognizer } from "@/hooks/useGestureRecognizer";
     8→import { usePoseDetection } from "@/hooks/usePoseDetection";
     9→import { useMiraVideoAvatar } from "@/hooks/useMiraVideoAvatar";
    10→import { useDeepgramSTT } from "@/hooks/useDeepgramSTT";
    11→import { parseEmotionTag, detectEmotionFromText } from "@/lib/emotion-parser";
    12→import { MiraVideoAvatar } from "@/components/ui/mira-video-avatar";
    13→import { GestureIndicator } from "@/components/mirror/GestureIndicator";
    14→import { ClothingCanvas, type FitMethod } from "@/components/mirror/ClothingCanvas";
    15→import { DebugOverlay } from "@/components/mirror/DebugOverlay";
    16→import { SpeechDisplay } from "@/components/mirror/SpeechDisplay";
    17→import { OutfitDots } from "@/components/mirror/OutfitDots";
    18→import VoiceIndicator from "@/components/mirror/VoiceIndicator";
    19→import PriceStrip, { type PriceStripItem } from "@/components/mirror/PriceStrip";
    20→import SessionRecap from "@/components/mirror/SessionRecap";
    21→import { socket } from "@/lib/socket";
    22→import { skipQueueUser } from "@/lib/api";
    23→import type { DetectedGesture, GestureType } from "@/types/gestures";
    24→import type { PoseResult } from "@/types/pose";
    25→import type { ClothingItem } from "@/types/clothing";
    26→import { mapToClothingItems } from "@/lib/map-clothing-items";
    27→
    28→type KioskState = "attract" | "waiting" | "session" | "recap";
    29→
    30→interface ActiveUser {
    31→  id: string;
    32→  name: string;
    33→}
    34→
    35→const PHONE_URL = process.env.NEXT_PUBLIC_PHONE_URL || "https://mirrorless.vercel.app/phone";
    36→const WAITING_TIMEOUT_MS = 2 * 60 * 1000; // 2 minutes
    37→const CANVAS_WIDTH = 1920;
    38→const CANVAS_HEIGHT = 1080;
    39→
    40→export default function MirrorV2PageWrapper() {
    41→  return (
    42→    <Suspense fallback={null}>
    43→      <MirrorV2Page />
    44→    </Suspense>
    45→  );
    46→}
    47→
    48→function MirrorV2Page() {
    49→  // ── Kiosk state ──
    50→  const [kioskState, setKioskState] = useState<KioskState>("attract");
    51→  const [activeUser, setActiveUser] = useState<ActiveUser | null>(null);
    52→  const waitingTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    53→  const pendingQueueRef = useRef<ActiveUser | null | undefined>(undefined);
    54→
    55→  // ── Camera (hidden, 1080p for better pose accuracy) ──
    56→  const { videoRef, isReady: isCameraReady } = useCamera({ width: 1920, height: 1080 });
    57→
    58→  // ── Gesture recognition ──
    59→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    60→  const gestureKeyRef = useRef(0);
    61→  const [gestureKey, setGestureKey] = useState(0);
    62→
    63→  // ── Session state ──
    64→  const [sessionActive, setSessionActive] = useState(false);
    65→  const [isStarting, setIsStarting] = useState(false);
    66→
    67→  // ── Pose detection + clothing overlay ──
    68→  const [currentPose, setCurrentPose] = useState<PoseResult | null>(null);
    69→
    70→  interface CanvasOutfit {
    71→    name: string;
    72→    items: ClothingItem[];
    73→    productInfo: PriceStripItem[];
    74→  }
    75→  const [canvasOutfits, setCanvasOutfits] = useState<CanvasOutfit[]>([]);
    76→  const [canvasOutfitIndex, setCanvasOutfitIndex] = useState(0);
    77→  const activeCanvasOutfit = canvasOutfits[canvasOutfitIndex]?.items ?? [];
    78→  const activePriceItems = canvasOutfits[canvasOutfitIndex]?.productInfo ?? [];
    79→
    80→  // ── Outfit opacity for fade-in ──
    81→  const [outfitOpacity, setOutfitOpacity] = useState(1);
    82→
    83→  // ── Debug overlay ──
    84→  const [debugMode, setDebugMode] = useState(false);
    85→
    86→  // ── Fit status tracking ──
    87→  const [fitStatuses, setFitStatuses] = useState<Map<string, FitMethod>>(new Map());
    88→
    89→  // ── Recap state ──
    90→  const [recapData, setRecapData] = useState<{
    91→    summary?: string;
    92→    liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
    93→    stats?: { items_shown: number; likes: number; dislikes: number };
    94→    user_name?: string;
    95→  } | null>(null);
    96→
    97→  // ── Mira video avatar + voice ──
    98→  const mira = useMiraVideoAvatar();
    99→  const stt = useDeepgramSTT();
   100→
   101→  // ── Speech display state ──
   102→  const [speechText, setSpeechText] = useState("");
   103→  const [speechVisible, setSpeechVisible] = useState(false);
   104→  const speechFadeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   105→
   106→  // Queue transcripts while mira is speaking, send when quiet
   107→  const pendingTranscriptRef = useRef<string | null>(null);
   108→
   109→  // Sentence buffer for incremental TTS — flushes at sentence boundaries
   110→  const sentenceBufferRef = useRef<string>("");
   111→  // Track emotion for the current response (parsed from first chunk)
   112→  const currentEmotionRef = useRef<string>("idle");
   113→  // Track whether emotion has been parsed for this response
   114→  const emotionParsedRef = useRef(false);
   115→
   116→  // Current user ID for session
   117→  const userId = activeUser?.id ?? null;
   118→
   119→  // ── Pose detection callback ──
   120→  const handlePoseUpdate = useCallback((result: PoseResult) => {
   121→    setCurrentPose(result);
   122→  }, []);
   123→
   124→  usePoseDetection({
   125→    videoRef,
   126→    isVideoReady: isCameraReady,
   127→    onPoseUpdate: handlePoseUpdate,
   128→  });
   129→
   130→  // ── Fit status callback ──
   131→  const handleFitStatus = useCallback((statuses: Map<string, FitMethod>) => {
   132→    setFitStatuses(statuses);
   133→  }, []);
   134→
   135→  // ── Connect socket and join mirror room ──
   136→  useEffect(() => {
   137→    socket.connect();
   138→    socket.emit("join_mirror_room");
   139→
   140→    return () => {
   141→      socket.disconnect();
   142→    };
   143→  }, []);
   144→
   145→  // Join user-specific room when active user changes
   146→  useEffect(() => {
   147→    if (userId) {
   148→      socket.emit("join_room", { user_id: userId });
   149→    }
   150→  }, [userId]);
   151→
   152→  // ── Queue events (drives attract <-> waiting) ──
   153→  useEffect(() => {
   154→    const handleQueueUpdated = (data: {
   155→      active_user: ActiveUser | null;
   156→      queue: Array<{ id: string; user_id: string; name: string; position: number; status: string }>;
   157→    }) => {
   158→      console.log("[MirrorV2] queue_updated:", data);
   159→      if (kioskState === "session") return;
   160→
   161→      if (kioskState === "recap") {
   162→        pendingQueueRef.current = data.active_user ?? null;
   163→        return;
   164→      }
   165→
   166→      if (data.active_user) {
   167→        setActiveUser(data.active_user);
   168→        setKioskState("waiting");
   169→      } else {
   170→        setActiveUser(null);
   171→        setKioskState("attract");
   172→      }
   173→    };
   174→
   175→    socket.on("queue_updated", handleQueueUpdated);
   176→    return () => {
   177→      socket.off("queue_updated", handleQueueUpdated);
   178→    };
   179→  }, [kioskState]);
   180→
   181→  // ── 2-minute timeout in waiting state ──
   182→  useEffect(() => {
   183→    if (kioskState === "waiting" && activeUser) {
   184→      waitingTimerRef.current = setTimeout(() => {
   185→        console.log("[MirrorV2] Waiting timeout — auto-skipping user");
   186→        skipQueueUser(activeUser.id).catch(() => {});
   187→      }, WAITING_TIMEOUT_MS);
   188→    }
   189→    return () => {
   190→      if (waitingTimerRef.current) {
   191→        clearTimeout(waitingTimerRef.current);
   192→        waitingTimerRef.current = null;
   193→      }
   194→    };
   195→  }, [kioskState, activeUser]);
   196→
   197→  // ── Session active from backend ──
   198→  useEffect(() => {
   199→    const handleSessionActive = () => {
   200→      setKioskState("session");
   201→      setSessionActive(true);
   202→      setIsStarting(false);
   203→      setCanvasOutfits([]);
   204→      setCanvasOutfitIndex(0);
   205→      setOutfitOpacity(1);
   206→      setSpeechText("");
   207→      setSpeechVisible(false);
   208→      mira.startSession();
   209→      stt.startListening();
   210→    };
   211→
   212→    socket.on("session_active", handleSessionActive);
   213→    return () => {
   214→      socket.off("session_active", handleSessionActive);
   215→    };
   216→    // eslint-disable-next-line react-hooks/exhaustive-deps
   217→  }, []);
   218→
   219→  // ── Mira speech events (sentence-level streaming) ──
   220→  useEffect(() => {
   221→    // Regex for sentence boundaries: .!? followed by a space or end of string
   222→    const SENTENCE_BOUNDARY = /[.!?](?:\s|$)/;
   223→
   224→    /**
   225→     * Flush complete sentences from the buffer to TTS.
   226→     * Returns any remaining partial sentence left in the buffer.
   227→     */
   228→    function flushSentences(buffer: string, emotion: string): string {
   229→      let remaining = buffer;
   230→
   231→      while (true) {
   232→        const match = SENTENCE_BOUNDARY.exec(remaining);
   233→        if (!match) break;
   234→
   235→        // Split at the sentence boundary (include the punctuation)
   236→        const endIdx = match.index + match[0].length;
   237→        const sentence = remaining.slice(0, endIdx).trim();
   238→        remaining = remaining.slice(endIdx);
   239→
   240→        if (sentence) {
   241→          mira.speakQueued(sentence, emotion as ReturnType<typeof parseEmotionTag>["emotion"]);
   242→
   243→          // Show sentence on screen immediately
   244→          setSpeechText(sentence);
   245→          setSpeechVisible(true);
   246→          if (speechFadeTimerRef.current) {
   247→            clearTimeout(speechFadeTimerRef.current);
   248→          }
   249→        }
   250→      }
   251→
   252→      return remaining;
   253→    }
   254→
   255→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   256→      // Fallback session detection
   257→      if (!sessionActive && !isStarting) {
   258→        setKioskState("session");
   259→        setSessionActive(true);
   260→        setIsStarting(false);
   261→        mira.startSession();
   262→        stt.startListening();
   263→      }
   264→
   265→      if (data.is_chunk !== false) {
   266→        // ── Streaming chunk ──
   267→        if (!data.text) return;
   268→
   269→        sentenceBufferRef.current += data.text;
   270→
   271→        // Parse emotion from first chunk (where [emotion:X] tag appears)
   272→        if (!emotionParsedRef.current) {
   273→          const { emotion, cleanText } = parseEmotionTag(sentenceBufferRef.current);
   274→          if (emotion !== "idle") {
   275→            currentEmotionRef.current = emotion;
   276→            emotionParsedRef.current = true;
   277→            sentenceBufferRef.current = cleanText;
   278→          } else {
   279→            // Try keyword detection on accumulated text
   280→            const detected = detectEmotionFromText(sentenceBufferRef.current);
   281→            if (detected !== "idle") {
   282→              currentEmotionRef.current = detected;
   283→              emotionParsedRef.current = true;
   284→            }
   285→          }
   286→        }
   287→
   288→        // Flush any complete sentences to TTS immediately
   289→        sentenceBufferRef.current = flushSentences(
   290→          sentenceBufferRef.current,
   291→          currentEmotionRef.current,
   292→        );
   293→      } else {
   294→        // ── End of message ──
   295→        if (data.text) {
   296→          sentenceBufferRef.current += data.text;
   297→        }
   298→
   299→        // Parse emotion if we haven't yet (short responses)
   300→        if (!emotionParsedRef.current) {
   301→          const { emotion, cleanText } = parseEmotionTag(sentenceBufferRef.current);
   302→          currentEmotionRef.current = emotion === "idle"
   303→            ? detectEmotionFromText(sentenceBufferRef.current)
   304→            : emotion;
   305→          sentenceBufferRef.current = emotion !== "idle" ? cleanText : sentenceBufferRef.current;
   306→        }
   307→
   308→        // Flush any remaining text as the final sentence
   309→        const remainder = sentenceBufferRef.current.trim();
   310→        if (remainder) {
   311→          mira.speakQueued(remainder, currentEmotionRef.current as ReturnType<typeof parseEmotionTag>["emotion"]);
   312→          setSpeechText(remainder);
   313→          setSpeechVisible(true);
   314→          if (speechFadeTimerRef.current) {
   315→            clearTimeout(speechFadeTimerRef.current);
   316→          }
   317→        }
   318→
   319→        // Signal end of queue — drain callback will reset avatar state
   320→        mira.flushQueue();
   321→
   322→        // Reset for next response
   323→        sentenceBufferRef.current = "";
   324→        currentEmotionRef.current = "idle";
   325→        emotionParsedRef.current = false;
   326→      }
   327→    };
   328→
   329→    socket.on("mira_speech", handleSpeech);
   330→    return () => {
   331→      socket.off("mira_speech", handleSpeech);
   332→    };
   333→    // eslint-disable-next-line react-hooks/exhaustive-deps
   334→  }, [sessionActive, isStarting]);
   335→
   336→  // Fade out speech text 2s after mira stops speaking
   337→  useEffect(() => {
   338→    if (!mira.isSpeaking && speechVisible) {
   339→      speechFadeTimerRef.current = setTimeout(() => {
   340→        setSpeechVisible(false);
   341→      }, 2000);
   342→    }
   343→    return () => {
   344→      if (speechFadeTimerRef.current) {
   345→        clearTimeout(speechFadeTimerRef.current);
   346→        speechFadeTimerRef.current = null;
   347→      }
   348→    };
   349→  }, [mira.isSpeaking, speechVisible]);
   350→
   351→  // ── Tool result events (product recommendations) ──
   352→  useEffect(() => {
   353→    const handleToolResult = (data: {
   354→      type?: string;
   355→      tool?: string;
   356→      items?: { title: string; price?: string; [key: string]: unknown }[];
   357→      text?: string;
   358→      emotion?: string;
   359→      outfit_name?: string;
   360→    }) => {
   361→      if (data.type === "display_product" && data.items) {
   362→        const clothingItems = mapToClothingItems(data.items);
   363→        const priceInfo: PriceStripItem[] = data.items.map((it) => ({
   364→          title: it.title,
   365→          price: it.price,
   366→        }));
   367→        if (clothingItems.length > 0) {
   368→          // Fade in: set opacity to 0, then transition to 1
   369→          setOutfitOpacity(0);
   370→          setCanvasOutfits((prev) => {
   371→            const next = [
   372→              ...prev,
   373→              {
   374→                name: data.outfit_name || `Outfit ${prev.length + 1}`,
   375→                items: clothingItems,
   376→                productInfo: priceInfo,
   377→              },
   378→            ];
   379→            setCanvasOutfitIndex(next.length - 1);
   380→            return next;
   381→          });
   382→          // Ramp opacity to 1 after a frame
   383→          requestAnimationFrame(() => {
   384→            requestAnimationFrame(() => {
   385→              setOutfitOpacity(1);
   386→            });
   387→          });
   388→        }
   389→        return;
   390→      }
   391→    };
   392→
   393→    socket.on("tool_result", handleToolResult);
   394→    return () => {
   395→      socket.off("tool_result", handleToolResult);
   396→    };
   397→  }, []);
   398→
   399→  // ── Session ended — show recap ──
   400→  useEffect(() => {
   401→    const handleSessionEnded = (data?: {
   402→      summary?: string;
   403→      liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
   404→      stats?: { items_shown: number; likes: number; dislikes: number };
   405→      user_name?: string;
   406→    }) => {
   407→      stt.stopListening();
   408→      setSessionActive(false);
   409→      setCanvasOutfits([]);
   410→      setCanvasOutfitIndex(0);
   411→      setSpeechText("");
   412→      setSpeechVisible(false);
   413→
   414→      if (data && (data.summary || data.liked_items?.length || data.stats)) {
   415→        setRecapData(data);
   416→        setKioskState("recap");
   417→      } else {
   418→        mira.stopSession();
   419→        setActiveUser(null);
   420→        setKioskState("attract");
   421→      }
   422→    };
   423→
   424→    socket.on("session_ended", handleSessionEnded);
   425→    return () => {
   426→      socket.off("session_ended", handleSessionEnded);
   427→    };
   428→    // eslint-disable-next-line react-hooks/exhaustive-deps
   429→  }, []);
   430→
   431→  // ── Force end from admin ──
   432→  useEffect(() => {
   433→    const handleForceEnd = (data: { user_id?: string }) => {
   434→      if (userId && data.user_id === userId) {
   435→        socket.emit("end_session", { user_id: userId });
   436→      }
   437→    };
   438→
   439→    socket.on("session_force_end", handleForceEnd);
   440→    return () => {
   441→      socket.off("session_force_end", handleForceEnd);
   442→    };
   443→  }, [userId]);
   444→
   445→  // ── Flush queued transcripts when mira stops speaking ──
   446→  useEffect(() => {
   447→    if (!mira.isSpeaking && pendingTranscriptRef.current && userId) {
   448→      socket.emit("mirror_event", {
   449→        user_id: userId,
   450→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   451→      });
   452→      pendingTranscriptRef.current = null;
   453→    }
   454→  }, [mira.isSpeaking, userId]);
   455→
   456→  // ── Forward final STT transcripts ──
   457→  useEffect(() => {
   458→    if (!stt.transcript || !userId) return;
   459→
   460→    if (mira.isSpeaking) {
   461→      pendingTranscriptRef.current = stt.transcript;
   462→    } else {
   463→      socket.emit("mirror_event", {
   464→        user_id: userId,
   465→        event: { type: "voice", transcript: stt.transcript },
   466→      });
   467→    }
   468→    // eslint-disable-next-line react-hooks/exhaustive-deps
   469→  }, [stt.transcript, userId]);
   470→
   471→  // ── Snapshot handler ──
   472→  useEffect(() => {
   473→    const handleSnapshotRequest = () => {
   474→      const video = videoRef.current;
   475→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   476→
   477→      const canvas = document.createElement("canvas");
   478→      canvas.width = video.videoWidth;
   479→      canvas.height = video.videoHeight;
   480→      const ctx = canvas.getContext("2d");
   481→      if (!ctx) return;
   482→
   483→      ctx.drawImage(video, 0, 0);
   484→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   485→      const base64 = dataUrl.split(",")[1];
   486→
   487→      socket.emit("mirror_event", {
   488→        type: "snapshot",
   489→        image_base64: base64,
   490→        user_id: userId,
   491→      });
   492→    };
   493→
   494→    socket.on("request_snapshot", handleSnapshotRequest);
   495→    return () => {
   496→      socket.off("request_snapshot", handleSnapshotRequest);
   497→    };
   498→  }, [videoRef, userId]);
   499→
   500→  // ── Gesture handler ──
   501→  const handleGesture = useCallback(
   502→    (gesture: DetectedGesture) => {
   503→      setLastGesture(gesture.type);
   504→      gestureKeyRef.current += 1;
   505→      setGestureKey(gestureKeyRef.current);
   506→
   507→      if (canvasOutfits.length > 1) {
   508→        if (gesture.type === "swipe_left") {
   509→          setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   510→        } else if (gesture.type === "swipe_right") {
   511→          setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   512→        }
   513→      }
   514→
   515→      socket.emit("mirror_event", {
   516→        user_id: userId,
   517→        event: {
   518→          type: "gesture",
   519→          gesture: gesture.type,
   520→          confidence: gesture.confidence,
   521→          timestamp: gesture.timestamp,
   522→        },
   523→      });
   524→    },
   525→    [userId, canvasOutfits.length],
   526→  );
   527→
   528→  useGestureRecognizer({
   529→    videoRef,
   530→    isVideoReady: isCameraReady,
   531→    onGesture: handleGesture,
   532→  });
   533→
   534→  // ── Keyboard shortcuts ──
   535→  useEffect(() => {
   536→    function handleKeyDown(e: KeyboardEvent) {
   537→      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
   538→        return;
   539→      }
   540→
   541→      switch (e.key) {
   542→        case "d":
   543→        case "D":
   544→          setDebugMode((d) => !d);
   545→          break;
   546→
   547→        case "f":
   548→        case "F":
   549→          if (document.fullscreenElement) {
   550→            document.exitFullscreen();
   551→          } else {
   552→            document.documentElement.requestFullscreen();
   553→          }
   554→          break;
   555→
   556→        case "ArrowLeft":
   557→          if (canvasOutfits.length > 1) {
   558→            setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   559→          }
   560→          break;
   561→
   562→        case "ArrowRight":
   563→          if (canvasOutfits.length > 1) {
   564→            setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   565→          }
   566→          break;
   567→
   568→        case "r":
   569→        case "R":
   570→          setCanvasOutfitIndex(0);
   571→          break;
   572→
   573→        default: {
   574→          const num = parseInt(e.key);
   575→          if (num >= 1 && num <= 9 && num - 1 < canvasOutfits.length) {
   576→            setCanvasOutfitIndex(num - 1);
   577→          }
   578→        }
   579→      }
   580→    }
   581→
   582→    window.addEventListener("keydown", handleKeyDown);
   583→    return () => window.removeEventListener("keydown", handleKeyDown);
   584→  }, [canvasOutfits.length]);
   585→
   586→  // ── Start session handler ──
   587→  const handleStartSession = useCallback(() => {
   588→    if (!userId || isStarting || sessionActive) return;
   589→
   590→    // Unlock browser audio policy while we still have the user gesture context
   591→    const ctx = new AudioContext();
   592→    ctx.resume().then(() => ctx.close());
   593→
   594→    setIsStarting(true);
   595→    socket.emit("start_session", { user_id: userId });
   596→  }, [userId, isStarting, sessionActive]);
   597→
   598→  const handleSkipUser = useCallback(() => {
   599→    if (!activeUser) return;
   600→    skipQueueUser(activeUser.id).catch(() => {});
   601→  }, [activeUser]);
   602→
   603→  // ── Dismiss recap ──
   604→  const handleRecapDismiss = useCallback(() => {
   605→    mira.stopSession();
   606→    setRecapData(null);
   607→
   608→    const pending = pendingQueueRef.current;
   609→    pendingQueueRef.current = undefined;
   610→
   611→    if (pending) {
   612→      setActiveUser(pending);
   613→      setKioskState("waiting");
   614→    } else {
   615→      setActiveUser(null);
   616→      setKioskState("attract");
   617→    }
   618→    // eslint-disable-next-line react-hooks/exhaustive-deps
   619→  }, []);
   620→
   621→  return (
   622→    <main
   623→      style={{
   624→        position: "relative",
   625→        width: "100vw",
   626→        height: "100vh",
   627→        background: "#000",
   628→        overflow: "hidden",
   629→      }}
   630→    >
   631→      {/* Hidden camera feed (1x1 pixel, invisible — only used for pose detection) */}
   632→      <video
   633→        ref={videoRef}
   634→        autoPlay
   635→        playsInline
   636→        muted
   637→        style={{
   638→          position: "absolute",
   639→          top: 0,
   640→          left: 0,
   641→          width: 1,
   642→          height: 1,
   643→          opacity: 0,
   644→          pointerEvents: "none",
   645→        }}
   646→      />
   647→
   648→      {/* === ATTRACT STATE === */}
   649→      {kioskState === "attract" && (
   650→        <div
   651→          style={{
   652→            position: "absolute",
   653→            inset: 0,
   654→            zIndex: 20,
   655→            display: "flex",
   656→            flexDirection: "column",
   657→            alignItems: "center",
   658→            justifyContent: "center",
   659→            background: "#000",
   660→          }}
   661→        >
   662→          <h1
   663→            style={{
   664→              color: "#fff",
   665→              fontSize: "3rem",
   666→              fontWeight: 700,
   667→              marginBottom: 8,
   668→              letterSpacing: "-0.02em",
   669→            }}
   670→          >
   671→            Mirrorless
   672→          </h1>
   673→          <p style={{ color: "rgba(255,255,255,0.6)", fontSize: "1.2rem", marginBottom: 40 }}>
   674→            Your AI stylist
   675→          </p>
   676→
   677→          <div
   678→            style={{
   679→              background: "#fff",
   680→              borderRadius: 16,
   681→              padding: 20,
   682→              marginBottom: 24,
   683→            }}
   684→          >
   685→            <QRCodeSVG
   686→              value={PHONE_URL}
   687→              size={180}
   688→              level="M"
   689→              includeMargin={false}
   690→            />
   691→          </div>
   692→
   693→          <p style={{ color: "rgba(255,255,255,0.4)", fontSize: "0.9rem" }}>
   694→            Scan the QR code with your phone
   695→          </p>
   696→        </div>
   697→      )}
   698→
   699→      {/* === WAITING STATE === */}
   700→      {kioskState === "waiting" && activeUser && (
   701→        <div
   702→          style={{
   703→            position: "absolute",
   704→            inset: 0,
   705→            zIndex: 20,
   706→            display: "flex",
   707→            flexDirection: "column",
   708→            alignItems: "center",
   709→            justifyContent: "center",
   710→            background: "#000",
   711→          }}
   712→        >
   713→          <p style={{ color: "rgba(255,255,255,0.5)", fontSize: "1rem", marginBottom: 8 }}>
   714→            Up next
   715→          </p>
   716→          <h2 style={{ color: "#fff", fontSize: "2.5rem", fontWeight: 700, marginBottom: 40 }}>
   717→            {activeUser.name}
   718→          </h2>
   719→          <div style={{ display: "flex", gap: 16 }}>
   720→            <button
   721→              onClick={handleStartSession}
   722→              disabled={isStarting}
   723→              style={{
   724→                padding: "16px 48px",
   725→                fontSize: "1.2rem",
   726→                fontWeight: 600,
   727→                color: "#fff",
   728→                background: "rgba(100, 140, 255, 0.8)",
   729→                border: "none",
   730→                borderRadius: 12,
   731→                cursor: "pointer",
   732→                boxShadow: "0 4px 20px rgba(100, 140, 255, 0.4)",
   733→              }}
   734→            >
   735→              {isStarting ? "Starting..." : "Start Session"}
