   738→              onClick={handleSkipUser}
   739→              style={{
   740→                padding: "16px 32px",
   741→                fontSize: "1.2rem",
   742→                fontWeight: 600,
   743→                color: "#fff",
   744→                background: "rgba(255, 255, 255, 0.15)",
