   757→      {/* === SESSION STATE === */}
   758→
   759→      {/* Clothing overlay canvas (z-5) */}
   760→      {activeCanvasOutfit.length > 0 && currentPose && (
   761→        <div style={{ position: "absolute", inset: 0, zIndex: 5, transition: "opacity 500ms ease", opacity: outfitOpacity }}>
   762→          <ClothingCanvas
   763→            pose={currentPose}
   764→            items={activeCanvasOutfit}
   765→            width={CANVAS_WIDTH}
   766→            height={CANVAS_HEIGHT}
   767→            onFitStatus={handleFitStatus}
   768→          />
   769→        </div>
   770→      )}
   771→
   772→      {/* Debug overlay (z-6, toggle with 'd') */}
   773→      <div style={{ position: "absolute", inset: 0, zIndex: 6 }}>
   774→        <DebugOverlay
   775→          pose={currentPose}
   776→          items={activeCanvasOutfit}
   777→          width={CANVAS_WIDTH}
   778→          height={CANVAS_HEIGHT}
   779→          visible={debugMode}
   780→        />
   781→      </div>
   782→
   783→      {/* Mira Video Avatar (z-10, top-right corner) */}
   784→      {sessionActive && (
   785→        <div
   786→          style={{
   787→            position: "absolute",
   788→            top: 24,
   789→            right: 24,
   790→            zIndex: 10,
   791→          }}
   792→        >
   793→          <MiraVideoAvatar
   794→            emotion={mira.emotion}
   795→            state={mira.avatarState}
   796→            size={180}
   797→          />
   798→        </div>
   799→      )}
   800→
   801→      {/* Speech display (z-10, bottom-center, above price strip) */}
   802→      {sessionActive && (
   803→        <SpeechDisplay text={speechText} visible={speechVisible} />
   804→      )}
   805→
   806→      {/* Price strip (z-15, bottom) */}
   807→      {sessionActive && activePriceItems.length > 0 && (
   808→        <PriceStrip items={activePriceItems} />
   809→      )}
   810→
   811→      {/* Outfit dots (z-18, bottom) */}
   812→      <OutfitDots count={canvasOutfits.length} activeIndex={canvasOutfitIndex} />
   813→
   814→      {/* Voice indicator for user STT (z-15, bottom-left) */}
   815→      {sessionActive && (
   816→        <VoiceIndicator
   817→          isListening={stt.isListening}
   818→          interimTranscript={stt.interimTranscript}
   819→        />
   820→      )}
   821→
   822→      {/* Gesture visual feedback (z-20, center) */}
   823→      <GestureIndicator key={gestureKey} gesture={lastGesture} />
   824→
   825→      {/* === RECAP STATE === (z-25) */}
   826→      {recapData && (
   827→        <SessionRecap
   828→          summary={recapData.summary}
   829→          likedItems={recapData.liked_items || []}
   830→          stats={recapData.stats}
   831→          userName={recapData.user_name}
   832→          onDismiss={handleRecapDismiss}
   833→        />
   834→      )}
   835→
   836→      {/* Fit status indicator (bottom-right, debug-only) */}
   837→      {debugMode && fitStatuses.size > 0 && (
   838→        <div
   839→          style={{
   840→            position: "absolute",
   841→            bottom: 20,
   842→            right: 20,
   843→            padding: "8px 12px",
   844→            background: "rgba(0,0,0,0.7)",
   845→            borderRadius: 8,
   846→            color: "#fff",
   847→            fontSize: "0.75rem",
   848→            zIndex: 30,
   849→            fontFamily: "monospace",
   850→          }}
   851→        >
   852→          {Array.from(fitStatuses.entries()).map(([id, method]) => (
   853→            <div key={id}>
   854→              {id.slice(0, 8)}: {method === "precise" ? "anchor" : "quad"}
   855→            </div>
   856→          ))}
   857→        </div>
   858→      )}
   859→    </main>
   860→  );
   861→}
   862→
   863→/* ---------- Waiting Countdown ---------- */
   864→
   865→function WaitingCountdown() {
   866→  const [remaining, setRemaining] = useState(120);
   867→
   868→  useEffect(() => {
   869→    const timer = setInterval(() => {
   870→      setRemaining((s) => {
   871→        if (s <= 0) return 0;
   872→        return s - 1;
   873→      });
   874→    }, 1000);
   875→    return () => clearInterval(timer);
   876→  }, []);
   877→
   878→  const minutes = Math.floor(remaining / 60);
   879→  const seconds = remaining % 60;
   880→
   881→  return (
   882→    <p style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.9rem", marginTop: 24 }}>
   883→      Auto-skip in {minutes}:{String(seconds).padStart(2, "0")}
   884→    </p>
   885→  );
   886→}
