    95→  } | null>(null);
    96→
    97→  // ── Mira video avatar + voice ──
    98→  const mira = useMiraVideoAvatar();
    99→  const stt = useDeepgramSTT();
   100→
   101→  // ── Speech display state ──
   102→  const [speechText, setSpeechText] = useState("");
   103→  const [speechVisible, setSpeechVisible] = useState(false);
