   109→  // Sentence buffer for incremental TTS — flushes at sentence boundaries
   110→  const sentenceBufferRef = useRef<string>("");
   111→  // Track emotion for the current response (parsed from first chunk)
   112→  const currentEmotionRef = useRef<string>("idle");
   113→  // Track whether emotion has been parsed for this response
