   129→
   130→  // ── Fit status callback ──
   131→  const handleFitStatus = useCallback((statuses: Map<string, FitMethod>) => {
   132→    setFitStatuses(statuses);
   133→  }, []);
   134→
   135→  // ── Connect socket and join mirror room ──
   136→  useEffect(() => {
   137→    socket.connect();
   138→    socket.emit("join_mirror_room");
