   144→
   145→  // Join user-specific room when active user changes
   146→  useEffect(() => {
   147→    if (userId) {
   148→      socket.emit("join_room", { user_id: userId });
   149→    }
   150→  }, [userId]);
   151→
   152→  // ── Queue events (drives attract <-> waiting) ──
   153→  useEffect(() => {
   154→    const handleQueueUpdated = (data: {
   155→      active_user: ActiveUser | null;
   156→      queue: Array<{ id: string; user_id: string; name: string; position: number; status: string }>;
   157→    }) => {
   158→      console.log("[MirrorV2] queue_updated:", data);
   159→      if (kioskState === "session") return;
   160→
   161→      if (kioskState === "recap") {
   162→        pendingQueueRef.current = data.active_user ?? null;
   163→        return;
   164→      }
   165→
   166→      if (data.active_user) {
   167→        setActiveUser(data.active_user);
   168→        setKioskState("waiting");
   169→      } else {
   170→        setActiveUser(null);
   171→        setKioskState("attract");
   172→      }
   173→    };
   174→
   175→    socket.on("queue_updated", handleQueueUpdated);
   176→    return () => {
   177→      socket.off("queue_updated", handleQueueUpdated);
   178→    };
   179→  }, [kioskState]);
   180→
   181→  // ── 2-minute timeout in waiting state ──
   182→  useEffect(() => {
   183→    if (kioskState === "waiting" && activeUser) {
   184→      waitingTimerRef.current = setTimeout(() => {
