   213→    return () => {
   214→      socket.off("session_active", handleSessionActive);
   215→    };
   216→    // eslint-disable-next-line react-hooks/exhaustive-deps
   217→  }, []);
   218→
   219→  // ── Mira speech events (sentence-level streaming) ──
   220→  useEffect(() => {
   221→    // Regex for sentence boundaries: .!? followed by a space or end of string
   222→    const SENTENCE_BOUNDARY = /[.!?](?:\s|$)/;
   223→
   224→    /**
   225→     * Flush complete sentences from the buffer to TTS.
   226→     * Returns any remaining partial sentence left in the buffer.
   227→     */
   228→    function flushSentences(buffer: string, emotion: string): string {
   229→      let remaining = buffer;
   230→
   231→      while (true) {
   232→        const match = SENTENCE_BOUNDARY.exec(remaining);
   233→        if (!match) break;
   234→
   235→        // Split at the sentence boundary (include the punctuation)
   236→        const endIdx = match.index + match[0].length;
   237→        const sentence = remaining.slice(0, endIdx).trim();
   238→        remaining = remaining.slice(endIdx);
   239→
   240→        if (sentence) {
   241→          mira.speakQueued(sentence, emotion as ReturnType<typeof parseEmotionTag>["emotion"]);
   242→
   243→          // Show sentence on screen immediately
   244→          setSpeechText(sentence);
   245→          setSpeechVisible(true);
   246→          if (speechFadeTimerRef.current) {
   247→            clearTimeout(speechFadeTimerRef.current);
   248→          }
   249→        }
   250→      }
   251→
   252→      return remaining;
   253→    }
   254→
   255→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   256→      // Fallback session detection
   257→      if (!sessionActive && !isStarting) {
   258→        setKioskState("session");
   259→        setSessionActive(true);
   260→        setIsStarting(false);
   261→        mira.startSession();
   262→        stt.startListening();
   263→      }
   264→
   265→      if (data.is_chunk !== false) {
   266→        // ── Streaming chunk ──
   267→        if (!data.text) return;
   268→
   269→        sentenceBufferRef.current += data.text;
   270→
   271→        // Parse emotion from first chunk (where [emotion:X] tag appears)
   272→        if (!emotionParsedRef.current) {
   273→          const { emotion, cleanText } = parseEmotionTag(sentenceBufferRef.current);
   274→          if (emotion !== "idle") {
   275→            currentEmotionRef.current = emotion;
   276→            emotionParsedRef.current = true;
   277→            sentenceBufferRef.current = cleanText;
   278→          } else {
   279→            // Try keyword detection on accumulated text
   280→            const detected = detectEmotionFromText(sentenceBufferRef.current);
   281→            if (detected !== "idle") {
   282→              currentEmotionRef.current = detected;
   283→              emotionParsedRef.current = true;
   284→            }
   285→          }
   286→        }
   287→
   288→        // Flush any complete sentences to TTS immediately
   289→        sentenceBufferRef.current = flushSentences(
   290→          sentenceBufferRef.current,
   291→          currentEmotionRef.current,
   292→        );
   293→      } else {
   294→        // ── End of message ──
   295→        if (data.text) {
   296→          sentenceBufferRef.current += data.text;
   297→        }
   298→
   299→        // Parse emotion if we haven't yet (short responses)
   300→        if (!emotionParsedRef.current) {
   301→          const { emotion, cleanText } = parseEmotionTag(sentenceBufferRef.current);
   302→          currentEmotionRef.current = emotion === "idle"
   303→            ? detectEmotionFromText(sentenceBufferRef.current)
   304→            : emotion;
   305→          sentenceBufferRef.current = emotion !== "idle" ? cleanText : sentenceBufferRef.current;
   306→        }
   307→
   308→        // Flush any remaining text as the final sentence
   309→        const remainder = sentenceBufferRef.current.trim();
   310→        if (remainder) {
   311→          mira.speakQueued(remainder, currentEmotionRef.current as ReturnType<typeof parseEmotionTag>["emotion"]);
   312→          setSpeechText(remainder);
   313→          setSpeechVisible(true);
   314→          if (speechFadeTimerRef.current) {
   315→            clearTimeout(speechFadeTimerRef.current);
   316→          }
   317→        }
   318→
   319→        // Signal end of queue — drain callback will reset avatar state
   320→        mira.flushQueue();
   321→
   322→        // Reset for next response
   323→        sentenceBufferRef.current = "";
   324→        currentEmotionRef.current = "idle";
   325→        emotionParsedRef.current = false;
   326→      }
   327→    };
   328→
   329→    socket.on("mira_speech", handleSpeech);
   330→    return () => {
   331→      socket.off("mira_speech", handleSpeech);
   332→    };
   333→    // eslint-disable-next-line react-hooks/exhaustive-deps
   334→  }, [sessionActive, isStarting]);
   335→
   336→  // Fade out speech text 2s after mira stops speaking
   337→  useEffect(() => {
   338→    if (!mira.isSpeaking && speechVisible) {
   339→      speechFadeTimerRef.current = setTimeout(() => {
   340→        setSpeechVisible(false);
   341→      }, 2000);
   342→    }
   343→    return () => {
   344→      if (speechFadeTimerRef.current) {
   345→        clearTimeout(speechFadeTimerRef.current);
   346→        speechFadeTimerRef.current = null;
   347→      }
   348→    };
   349→  }, [mira.isSpeaking, speechVisible]);
   350→
   351→  // ── Tool result events (product recommendations) ──
   352→  useEffect(() => {
   353→    const handleToolResult = (data: {
   354→      type?: string;
   355→      tool?: string;
   356→      items?: { title: string; price?: string; [key: string]: unknown }[];
   357→      text?: string;
   358→      emotion?: string;
   359→      outfit_name?: string;
   360→    }) => {
   361→      if (data.type === "display_product" && data.items) {
   362→        const clothingItems = mapToClothingItems(data.items);
   363→        const priceInfo: PriceStripItem[] = data.items.map((it) => ({
   364→          title: it.title,
   365→          price: it.price,
   366→        }));
   367→        if (clothingItems.length > 0) {
   368→          // Fade in: set opacity to 0, then transition to 1
   369→          setOutfitOpacity(0);
   370→          setCanvasOutfits((prev) => {
   371→            const next = [
   372→              ...prev,
   373→              {
   374→                name: data.outfit_name || `Outfit ${prev.length + 1}`,
   375→                items: clothingItems,
   376→                productInfo: priceInfo,
   377→              },
   378→            ];
   379→            setCanvasOutfitIndex(next.length - 1);
   380→            return next;
   381→          });
   382→          // Ramp opacity to 1 after a frame
   383→          requestAnimationFrame(() => {
   384→            requestAnimationFrame(() => {
   385→              setOutfitOpacity(1);
   386→            });
   387→          });
   388→        }
   389→        return;
   390→      }
   391→    };
   392→
   393→    socket.on("tool_result", handleToolResult);
   394→    return () => {
   395→      socket.off("tool_result", handleToolResult);
   396→    };
   397→  }, []);
   398→
   399→  // ── Session ended — show recap ──
   400→  useEffect(() => {
   401→    const handleSessionEnded = (data?: {
   402→      summary?: string;
   403→      liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
   404→      stats?: { items_shown: number; likes: number; dislikes: number };
   405→      user_name?: string;
   406→    }) => {
   407→      stt.stopListening();
   408→      setSessionActive(false);
   409→      setCanvasOutfits([]);
   410→      setCanvasOutfitIndex(0);
   411→      setSpeechText("");
   412→      setSpeechVisible(false);
   413→
   414→      if (data && (data.summary || data.liked_items?.length || data.stats)) {
   415→        setRecapData(data);
   416→        setKioskState("recap");
   417→      } else {
   418→        mira.stopSession();
   419→        setActiveUser(null);
   420→        setKioskState("attract");
   421→      }
   422→    };
   423→
   424→    socket.on("session_ended", handleSessionEnded);
   425→    return () => {
   426→      socket.off("session_ended", handleSessionEnded);
   427→    };
   428→    // eslint-disable-next-line react-hooks/exhaustive-deps
   429→  }, []);
   430→
   431→  // ── Force end from admin ──
   432→  useEffect(() => {
   433→    const handleForceEnd = (data: { user_id?: string }) => {
   434→      if (userId && data.user_id === userId) {
   435→        socket.emit("end_session", { user_id: userId });
   436→      }
   437→    };
   438→
   439→    socket.on("session_force_end", handleForceEnd);
   440→    return () => {
   441→      socket.off("session_force_end", handleForceEnd);
   442→    };
   443→  }, [userId]);
   444→
   445→  // ── Flush queued transcripts when mira stops speaking ──
   446→  useEffect(() => {
   447→    if (!mira.isSpeaking && pendingTranscriptRef.current && userId) {
   448→      socket.emit("mirror_event", {
   449→        user_id: userId,
   450→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   451→      });
   452→      pendingTranscriptRef.current = null;
   453→    }
   454→  }, [mira.isSpeaking, userId]);
   455→
   456→  // ── Forward final STT transcripts ──
   457→  useEffect(() => {
   458→    if (!stt.transcript || !userId) return;
   459→
   460→    if (mira.isSpeaking) {
   461→      pendingTranscriptRef.current = stt.transcript;
   462→    } else {
   463→      socket.emit("mirror_event", {
   464→        user_id: userId,
   465→        event: { type: "voice", transcript: stt.transcript },
   466→      });
   467→    }
   468→    // eslint-disable-next-line react-hooks/exhaustive-deps
   469→  }, [stt.transcript, userId]);
   470→
   471→  // ── Snapshot handler ──
   472→  useEffect(() => {
   473→    const handleSnapshotRequest = () => {
   474→      const video = videoRef.current;
   475→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   476→
   477→      const canvas = document.createElement("canvas");
   478→      canvas.width = video.videoWidth;
   479→      canvas.height = video.videoHeight;
   480→      const ctx = canvas.getContext("2d");
   481→      if (!ctx) return;
   482→
   483→      ctx.drawImage(video, 0, 0);
   484→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   485→      const base64 = dataUrl.split(",")[1];
   486→
   487→      socket.emit("mirror_event", {
   488→        type: "snapshot",
   489→        image_base64: base64,
   490→        user_id: userId,
   491→      });
   492→    };
   493→
   494→    socket.on("request_snapshot", handleSnapshotRequest);
   495→    return () => {
   496→      socket.off("request_snapshot", handleSnapshotRequest);
   497→    };
   498→  }, [videoRef, userId]);
   499→
   500→  // ── Gesture handler ──
   501→  const handleGesture = useCallback(
   502→    (gesture: DetectedGesture) => {
   503→      setLastGesture(gesture.type);
   504→      gestureKeyRef.current += 1;
   505→      setGestureKey(gestureKeyRef.current);
   506→
   507→      if (canvasOutfits.length > 1) {
   508→        if (gesture.type === "swipe_left") {
   509→          setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   510→        } else if (gesture.type === "swipe_right") {
   511→          setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   512→        }
   513→      }
   514→
   515→      socket.emit("mirror_event", {
   516→        user_id: userId,
   517→        event: {
   518→          type: "gesture",
   519→          gesture: gesture.type,
   520→          confidence: gesture.confidence,
   521→          timestamp: gesture.timestamp,
   522→        },
   523→      });
   524→    },
   525→    [userId, canvasOutfits.length],
   526→  );
   527→
   528→  useGestureRecognizer({
   529→    videoRef,
   530→    isVideoReady: isCameraReady,
   531→    onGesture: handleGesture,
   532→  });
   533→
   534→  // ── Keyboard shortcuts ──
   535→  useEffect(() => {
   536→    function handleKeyDown(e: KeyboardEvent) {
   537→      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
   538→        return;
   539→      }
   540→
   541→      switch (e.key) {
   542→        case "d":
   543→        case "D":
   544→          setDebugMode((d) => !d);
   545→          break;
   546→
   547→        case "f":
   548→        case "F":
   549→          if (document.fullscreenElement) {
   550→            document.exitFullscreen();
   551→          } else {
   552→            document.documentElement.requestFullscreen();
   553→          }
   554→          break;
   555→
   556→        case "ArrowLeft":
   557→          if (canvasOutfits.length > 1) {
   558→            setCanvasOutfitIndex((i) => (i - 1 + canvasOutfits.length) % canvasOutfits.length);
   559→          }
   560→          break;
   561→
   562→        case "ArrowRight":
   563→          if (canvasOutfits.length > 1) {
   564→            setCanvasOutfitIndex((i) => (i + 1) % canvasOutfits.length);
   565→          }
   566→          break;
   567→
   568→        case "r":
   569→        case "R":
   570→          setCanvasOutfitIndex(0);
   571→          break;
   572→
   573→        default: {
   574→          const num = parseInt(e.key);
   575→          if (num >= 1 && num <= 9 && num - 1 < canvasOutfits.length) {
   576→            setCanvasOutfitIndex(num - 1);
   577→          }
   578→        }
   579→      }
   580→    }
   581→
   582→    window.addEventListener("keydown", handleKeyDown);
   583→    return () => window.removeEventListener("keydown", handleKeyDown);
   584→  }, [canvasOutfits.length]);
   585→
   586→  // ── Start session handler ──
   587→  const handleStartSession = useCallback(() => {
   588→    if (!userId || isStarting || sessionActive) return;
   589→
   590→    // Unlock browser audio policy while we still have the user gesture context
   591→    const ctx = new AudioContext();
   592→    ctx.resume().then(() => ctx.close());
   593→
   594→    setIsStarting(true);
   595→    socket.emit("start_session", { user_id: userId });
   596→  }, [userId, isStarting, sessionActive]);
   597→
   598→  const handleSkipUser = useCallback(() => {
   599→    if (!activeUser) return;
   600→    skipQueueUser(activeUser.id).catch(() => {});
   601→  }, [activeUser]);
   602→
   603→  // ── Dismiss recap ──
   604→  const handleRecapDismiss = useCallback(() => {
   605→    mira.stopSession();
   606→    setRecapData(null);
   607→
   608→    const pending = pendingQueueRef.current;
   609→    pendingQueueRef.current = undefined;
   610→
   611→    if (pending) {
   612→      setActiveUser(pending);
   613→      setKioskState("waiting");
   614→    } else {
   615→      setActiveUser(null);
   616→      setKioskState("attract");
   617→    }
   618→    // eslint-disable-next-line react-hooks/exhaustive-deps
   619→  }, []);
   620→
   621→  return (
   622→    <main
   623→      style={{
   624→        position: "relative",
   625→        width: "100vw",
   626→        height: "100vh",
   627→        background: "#000",
   628→        overflow: "hidden",
   629→      }}
   630→    >
   631→      {/* Hidden camera feed (1x1 pixel, invisible — only used for pose detection) */}
   632→      <video
   633→        ref={videoRef}
   634→        autoPlay
   635→        playsInline
   636→        muted
   637→        style={{
   638→          position: "absolute",
   639→          top: 0,
   640→          left: 0,
   641→          width: 1,
   642→          height: 1,
   643→          opacity: 0,
   644→          pointerEvents: "none",
   645→        }}
   646→      />
   647→
   648→      {/* === ATTRACT STATE === */}
   649→      {kioskState === "attract" && (
   650→        <div
   651→          style={{
   652→            position: "absolute",
   653→            inset: 0,
   654→            zIndex: 20,
   655→            display: "flex",
   656→            flexDirection: "column",
   657→            alignItems: "center",
   658→            justifyContent: "center",
   659→            background: "#000",
   660→          }}
   661→        >
   662→          <h1
   663→            style={{
   664→              color: "#fff",
   665→              fontSize: "3rem",
   666→              fontWeight: 700,
   667→              marginBottom: 8,
   668→              letterSpacing: "-0.02em",
   669→            }}
   670→          >
   671→            Mirrorless
   672→          </h1>
   673→          <p style={{ color: "rgba(255,255,255,0.6)", fontSize: "1.2rem", marginBottom: 40 }}>
   674→            Your AI stylist
   675→          </p>
   676→
   677→          <div
   678→            style={{
   679→              background: "#fff",
   680→              borderRadius: 16,
   681→              padding: 20,
   682→              marginBottom: 24,
   683→            }}
   684→          >
   685→            <QRCodeSVG
   686→              value={PHONE_URL}
   687→              size={180}
   688→              level="M"
   689→              includeMargin={false}
   690→            />
   691→          </div>
   692→
   693→          <p style={{ color: "rgba(255,255,255,0.4)", fontSize: "0.9rem" }}>
   694→            Scan the QR code with your phone
   695→          </p>
