   698→
   699→      {/* === WAITING STATE === */}
   700→      {kioskState === "waiting" && activeUser && (
   701→        <div
   702→          style={{
   703→            position: "absolute",
   704→            inset: 0,
   705→            zIndex: 20,
   706→            display: "flex",
   707→            flexDirection: "column",
   708→            alignItems: "center",
   709→            justifyContent: "center",
   710→            background: "#000",
   711→          }}
   712→        >
   713→          <p style={{ color: "rgba(255,255,255,0.5)", fontSize: "1rem", marginBottom: 8 }}>
   714→            Up next
   715→          </p>
   716→          <h2 style={{ color: "#fff", fontSize: "2.5rem", fontWeight: 700, marginBottom: 40 }}>
   717→            {activeUser.name}
   718→          </h2>
   719→          <div style={{ display: "flex", gap: 16 }}>
   720→            <button
   721→              onClick={handleStartSession}
   722→              disabled={isStarting}
   723→              style={{
   724→                padding: "16px 48px",
   725→                fontSize: "1.2rem",
   726→                fontWeight: 600,
   727→                color: "#fff",
   728→                background: "rgba(100, 140, 255, 0.8)",
   729→                border: "none",
   730→                borderRadius: 12,
   731→                cursor: "pointer",
   732→                boxShadow: "0 4px 20px rgba(100, 140, 255, 0.4)",
   733→              }}
   734→            >
   735→              {isStarting ? "Starting..." : "Start Session"}
   736→            </button>
