          setCanvasOutfitIndex(next.length - 1);
          return next;
        });
        // Ramp opacity to 1 after a frame
        requestAnimationFrame(() => {
          requestAnimationFrame(() => {
            setOutfitOpacity(1);
          });
        });
      }
      return;
    }
  };

  socket.on("tool_result", handleToolResult);
  return () => {
    socket.off("tool_result", handleToolResult);
  };
}, []);

